"use client";

import Head from "next/head";

export default function TermsOfService() {
  return (
    <>
      {/* ✅ SEO Meta Tags */}
      <Head>
        <title>Terms of Service | Your Brand</title>
        <meta
          name="description"
          content="Read the Terms of Service for using our website, services, and mobile app. Learn about your rights, responsibilities, and account guidelines."
        />
        <meta name="robots" content="index, follow" />
        <meta property="og:title" content="Terms of Service | Your Brand" />
        <meta
          property="og:description"
          content="Read the Terms of Service for using our website, services, and mobile app."
        />
        <meta property="og:type" content="website" />
        <meta
          property="og:url"
          content="https://yourdomain.com/terms-of-service"
        />
        <meta property="og:site_name" content="Your Brand" />
      </Head>

      {/* ✅ Gradient Header Section */}
      <header className="tos-header text-center py-5">
        <div className="container">
          <h1 className="fw-bold text-uppercase">Terms of Service</h1>
          <p className="updated-date">Updated: May 25, 2018</p>
        </div>
      </header>

      {/* ✅ White Background Content */}
      <section className="tos-section py-5">
        <div className="container">
          <div className="tos-content p-4 shadow-sm bg-white rounded">
            <p>
              This Terms of Service (the “Terms”) describes the rights and
              responsibilities that apply to your use of our websites,
              services, and mobile applications (collectively, the “Service”),
              each owned and operated by <strong>Your Brand</strong> (“we,”
              “our,” or “us”).
            </p>

            <p>
              Please read these Terms carefully before using the Service. If
              you don’t agree to the Terms, you may not use the Service. If you
              are entering into these Terms on behalf of a company or other
              legal entity, you represent that you have the authority to bind
              such entity to the Terms.
            </p>

            <h2 className="fw-semibold mt-4">1. Account Responsibilities</h2>
            <p>
              If you create an account, you are responsible for maintaining its
              security and for all activities that occur under your account.
              You must not use your account in a misleading or unlawful manner.
            </p>

            <h2 className="fw-semibold mt-4">2. Content Ownership</h2>
            <p>
              You retain ownership of the content you post on our platform.
              However, by posting content, you grant us a non-exclusive,
              worldwide, royalty-free license to use, reproduce, and distribute
              your content in connection with the Service.
            </p>

            <h2 className="fw-semibold mt-4">3. Termination</h2>
            <p>
              We reserve the right to suspend or terminate your account if you
              violate these Terms of Service or engage in unlawful activity.
            </p>
          </div>
        </div>
      </section>
    </>
  );
}
